class Counter extends React.Component {
  constructor(props) {
    super(props);
    this.state = { count: 0, name: '' };
  }

  increment() {
    // Updater form — safe when next state depends on previous
    this.setState(prev => ({ count: prev.count + 1 }));
  }

  render() {
    return <button onClick={() => this.increment()}>{this.state.count}</button>;
  }
}

function Counter() {
  const [count, setCount] = useState(0);
  const [name, setName] = useState('');

  // Functional update form — no dependency on stale closure
  const increment = () => setCount(prev => prev + 1);

  return <button onClick={increment}>{count}</button>;
}

class DataLoader extends React.Component {
  componentDidMount() {
    // fetch AND subscribe in the same method — unrelated concerns mixed
    this.fetchData();
    this.subscription = subscribe(this.props.channel, this.handleMsg);
  }

  componentDidUpdate(prevProps) {
    if (prevProps.url !== this.props.url) this.fetchData();
    if (prevProps.channel !== this.props.channel) {
      unsubscribe(this.subscription);
      this.subscription = subscribe(this.props.channel, this.handleMsg);
    }
  }

  componentWillUnmount() {
    // cleanup is split across a different method
    unsubscribe(this.subscription);
  }
}

function DataLoader({ url, channel }) {
  // Effect 1: data fetching — one concern, co-located
  useEffect(() => {
    let cancelled = false;
    fetch(url).then(r => r.json()).then(data => {
      if (!cancelled) setData(data);
    });
    return () => { cancelled = true; };
  }, [url]);

  // Effect 2: subscription — separate concern, separate effect
  useEffect(() => {
    const sub = subscribe(channel, handleMsg);
    return () => unsubscribe(sub); // cleanup lives right here
  }, [channel]);
}

// HOC adds extra component layer in DevTools
function withAuth(WrappedComponent) {
  return class extends React.Component {
    render() {
      const user = getCurrentUser();
      return <WrappedComponent {...this.props} user={user} />;
    }
  };
}

// Nesting quickly becomes deep
export default withTheme(withAuth(withData(MyComponent)));

// Custom hook — a plain function, no wrapper component
function useAuth() {
  const [user, setUser] = useState(null);
  useEffect(() => {
    const unsubscribe = authService.onAuthStateChanged(setUser);
    return unsubscribe;
  }, []);
  return user;
}

// Usage: no HOC wrapping, no extra DevTools layer
function Profile() {
  const user = useAuth();           // stateful logic as a function call
  const theme = useTheme();         // multiple hooks compose cleanly
  const { data } = useUserData(user?.id);
  return <div>{data?.name}</div>;
}

// Class: contextType limits you to one context
class Toolbar extends React.Component {
  static contextType = ThemeContext;
  render() {
    const theme = this.context;  // can only read one context this way
    return <div style={{ color: theme.primary }}>...</div>;
  }
}

// Hooks: useContext for each context — unlimited, clean
function Toolbar() {
  const theme = useContext(ThemeContext);
  const user  = useContext(UserContext);
  const lang  = useContext(LanguageContext);
  return <div style={{ color: theme.primary }}>{lang.greeting}, {user.name}</div>;
}

// PureComponent does shallow comparison of props + state
class ExpensiveList extends React.PureComponent {
  render() { return <ul>{this.props.items.map(i => <li key={i.id}>{i.label}</li>)}</ul>; }
}

// Manual control via shouldComponentUpdate
class Custom extends React.Component {
  shouldComponentUpdate(nextProps) {
    return nextProps.value !== this.props.value;
  }
}

// React.memo: shallow prop comparison (equivalent to PureComponent)
const ExpensiveList = React.memo(function ExpensiveList({ items }) {
  return <ul>{items.map(i => <li key={i.id}>{i.label}</li>)}</ul>;
});

function Parent({ data }) {
  // useMemo: memoize a computed value
  const sorted = useMemo(() => [...data].sort((a, b) => a.label.localeCompare(b.label)), [data]);

  // useCallback: stable function reference for memo'd children
  const handleClick = useCallback((id) => { console.log(id); }, []);

  return <ExpensiveList items={sorted} onSelect={handleClick} />;
}

// Error boundaries must be class components — no hook equivalent
class ErrorBoundary extends React.Component {
  state = { hasError: false, error: null };

  static getDerivedStateFromError(error) {
    return { hasError: true, error };
  }

  componentDidCatch(error, info) {
    logErrorToService(error, info.componentStack);
  }

  render() {
    if (this.state.hasError) return <FallbackUI error={this.state.error} />;
    return this.props.children;
  }
}

// Used in function component trees just fine
function App() {
  return (
    <ErrorBoundary>
      <Dashboard />
    </ErrorBoundary>
  );
}

// Enzyme-style: reaches into component internals
import { shallow } from 'enzyme';
const wrapper = shallow(<Counter />);
wrapper.instance().increment();  // calls method directly
expect(wrapper.state('count')).toBe(1);

// React Testing Library: drives via the UI
import { render, screen, fireEvent } from '@testing-library/react';

test('counter increments on click', () => {
  render(<Counter />);
  fireEvent.click(screen.getByRole('button'));
  expect(screen.getByRole('button')).toHaveTextContent('1');
});

// Testing a custom hook in isolation
import { renderHook, act } from '@testing-library/react';
test('useCounter increments', () => {
  const { result } = renderHook(() => useCounter(0));
  act(() => result.current.increment());
  expect(result.current.count).toBe(1);
});
